public int findNthDigit(int n) {
    int size = 1;
    long length = 9;
    int start = 1;

    while (n > length * size) {
        n -= length * size;
        size++;
        length *= 10;
        start *= 10;
    }

    start += (n - 1) / size;
    String s = Integer.toString(start);
    return Character.getNumericValue(s.charAt((n - 1) % size));
}
```

